proposals.codeSnippet:
// 'FrutigerNext LT Regular' → family='FrutigerNext LT', style=Normal
using var typeface = SKTypeface.FromFamilyName("FrutigerNext LT", SKFontStyle.Normal);

// 'FrutigerNext LT Heavy' → family='FrutigerNext LT', weight=900
using var heavy = SKTypeface.FromFamilyName("FrutigerNext LT", new SKFontStyle(900, 5, SKFontStyleSlant.Upright));

// Check if the requested font was actually matched (Skia silently returns a fallback)
if (typeface?.FamilyName != "FrutigerNext LT")
    throw new InvalidOperationException("Font not installed on this system.");

SKTypeface FindTypefaceByFullName(string fullFontName)
{
    var fm = SKFontManager.Default;
    foreach (var familyName in fm.FontFamilies)
    {
        using var styleSet = fm.GetFontStyles(familyName);
        for (int i = 0; i < styleSet.Count; i++)
        {
            var styleName = styleSet.GetStyleName(i);
            if (styleName == null) continue;
            if (string.Equals($"{familyName} {styleName}", fullFontName,
                    StringComparison.OrdinalIgnoreCase))
            {
                var tf = styleSet.CreateTypeface(i);
                if (tf != null) return tf;
            }
        }
    }
    return null; // Font not installed on this system
}

// Usage:
var typeface = FindTypefaceByFullName("FrutigerNext LT Regular");
// Note: fonts must be installed on the system (or pre-registered via SKFontManager).
// Not supported on WASM; mobile platforms require fonts to be embedded in the app bundle.

actions.comment:
Hi @Jack-Paul,

The key distinction in Skia's font model is between a **font family name** (e.g., `FrutigerNext LT`) and a **full font name** (e.g., `FrutigerNext LT Regular`). `SKTypeface.FromFamilyName()` expects only the family name portion, with the style (weight/slant) supplied separately via `SKFontStyle`.

**Option 1 — If you know the family and style:**

```csharp
// 'FrutigerNext LT Regular'
using var typeface = SKTypeface.FromFamilyName("FrutigerNext LT", SKFontStyle.Normal);

// 'FrutigerNext LT Heavy' (weight 900)
using var heavy = SKTypeface.FromFamilyName("FrutigerNext LT",
    new SKFontStyle(900, 5, SKFontStyleSlant.Upright));

// Important: Skia returns a fallback font silently if the family isn't found.
// Check that the result matches what you requested:
if (typeface?.FamilyName != "FrutigerNext LT")
    throw new InvalidOperationException("Font not installed on this system.");
```

**Option 2 — Resolve any full font name generically (family name unknown):**

```csharp
SKTypeface FindTypefaceByFullName(string fullFontName)
{
    var fm = SKFontManager.Default;
    foreach (var familyName in fm.FontFamilies)
    {
        using var styleSet = fm.GetFontStyles(familyName);
        for (int i = 0; i < styleSet.Count; i++)
        {
            var styleName = styleSet.GetStyleName(i);
            if (styleName == null) continue;
            if (string.Equals($"{familyName} {styleName}", fullFontName,
                    StringComparison.OrdinalIgnoreCase))
            {
                var tf = styleSet.CreateTypeface(i);
                if (tf != null) return tf;
            }
        }
    }
    return null; // font not found
}

// Usage:
var typeface = FindTypefaceByFullName("FrutigerNext LT Regular");
```

**Important platform notes:**
- Fonts must be **installed on the system** (Windows/macOS/Linux) for `FontFamilies` enumeration to see them.
- On **Android/iOS**, system fonts are limited — custom fonts must be embedded in the app bundle and loaded via `SKTypeface.FromStream()` or `SKTypeface.FromFile()`.
- **WASM** does not support runtime font enumeration — fonts must be embedded at build time.
- On **Linux**, `fontconfig` must be installed and the font cache updated (`fc-cache -fv`) for custom fonts to be visible.
